import { Chart as ChartJS, ArcElement, Tooltip, Legend } from 'chart.js'
import { Doughnut } from 'react-chartjs-2'
import ChartDataLabels from 'chartjs-plugin-datalabels'
import React, { useState, useEffect, useRef } from "react";
import { API_BASE_URL } from '../../config/config';
import axios from "axios";

ChartJS.register(ArcElement, Tooltip, Legend, ChartDataLabels)

const CHART_COLORS = [
  '#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0', '#9966FF', '#FF9F40',
  '#8AC926', '#1982C4', '#6A0572'
];

// ✅ Fixed type colors — consistent everywhere
const TYPE_COLOR_MAP = {
  founder: '#36A2EB',
  option_pool: '#4BC0C0',
  pending: '#FFC107',
  new_investor: '#8AC926',
  converted: '#9966FF',
  previous_investor: '#FF6384',
  other: '#FF9F40',
};

// ✅ Get color for an expanded item — same logic used in both chart data and legend
function getItemColor(item, fallbackIndex) {
  if (item._type === 'founder') return TYPE_COLOR_MAP.founder;
  if (item._type === 'option_pool') return TYPE_COLOR_MAP.option_pool;
  if (item._type === 'pending') return TYPE_COLOR_MAP.pending;
  if (item._isNew) return TYPE_COLOR_MAP.new_investor;
  if (item._isConverted) return TYPE_COLOR_MAP.converted;
  if (item._isPrevious) return TYPE_COLOR_MAP.previous_investor;
  return CHART_COLORS[fallbackIndex % CHART_COLORS.length];
}

// ✅ Group type label for legend
function getTypeLabel(item) {
  if (item._type === 'founder') return 'Founders';
  if (item._type === 'option_pool') return 'Option Pool';
  if (item._type === 'pending') return 'Pending SAFE';
  if (item._isNew) return 'New Investors';
  if (item._isConverted) return 'Converted';
  if (item._isPrevious) return 'Previous Investors';
  return 'Other';
}

export default function RoundStatistics() {

  const apiUrlRound = API_BASE_URL + "api/user/companydashboard/";
  const storedUsername = localStorage.getItem("SignatoryLoginData");
  const userLogin = storedUsername ? JSON.parse(storedUsername) : null;
  const access_token = userLogin?.access_token;

  const [postMoneyChartData, setPostMoneyChartData] = useState(null);
  const [postMoneyChartOptions, setPostMoneyChartOptions] = useState(null);
  const chartRef = useRef(null);

  useEffect(() => {
    getroundChart();
  }, []);

  const getroundChart = async () => {
    let formData = { company_id: userLogin.companies[0].id };

    try {
      const res = await axios.post(
        apiUrlRound + "getroundChart",
        formData,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
            'Authorization': `Bearer ${access_token}`,
          },
        }
      );

      const capTable = res.data.cap_table || { post_money: { items: [] } };

      if (!capTable?.post_money?.items?.length) return;

      // ── Expand items ────────────────────────────────────────────────────
      const expandedItems = [];

      capTable.post_money.items.forEach((item) => {
        if (item.type === 'investor') {
          const inv = item.investor_details || {};
          const name = `${inv.firstName || ''} ${inv.lastName || ''}`.trim() || item.name || 'Investor';
          expandedItems.push({
            ...item,
            _displayName: `👤 ${name}`,
            _shares: item.shares || 0,
            _type: 'investor',
            _isNew: item.is_new_investment,
            _isPrevious: item.is_previous,
            _isConverted: item.is_converted,
          });
        } else if (item.type === 'founder') {
          expandedItems.push({
            ...item,
            _displayName: item.name,
            _shares: item.shares || 0,
            _type: 'founder',
          });
        } else if (item.type === 'option_pool') {
          expandedItems.push({
            ...item,
            _displayName: 'Employee Option Pool',
            _shares: item.shares || 0,
            _type: 'option_pool',
          });
        } else if (item.type === 'pending_group') {
          (item.items || []).forEach(inv => {
            expandedItems.push({
              ...inv,
              _displayName: `⏳ ${inv.name}`,
              _shares: 0,
              _type: 'pending',
            });
          });
        }
      });

      const totalShares = expandedItems.reduce((sum, item) => sum + (item._shares || 0), 0);

      // ── ✅ Colors assigned per item — same source for chart + legend ──
      const itemColors = expandedItems.map((item, i) => getItemColor(item, i));

      // ── Chart data ──────────────────────────────────────────────────────
      const postMoneyData = {
        labels: expandedItems.map(item => item._displayName),
        datasets: [{
          label: 'Shares',
          data: expandedItems.map(item => item._shares),
          backgroundColor: itemColors,
          borderWidth: 1,
        }],
      };

      setPostMoneyChartData(postMoneyData);

      // ── ✅ Build grouped legend from same expandedItems + itemColors ────
      // Group by type, accumulate shares + indices
      const typeGroups = {};
      expandedItems.forEach((item, i) => {
        const label = getTypeLabel(item);
        if (!typeGroups[label]) {
          typeGroups[label] = {
            shares: 0,
            color: itemColors[i],   // ✅ color from same source
            indices: [],            // dataset indices for click toggle
          };
        }
        typeGroups[label].shares += item._shares || 0;
        typeGroups[label].indices.push(i);
      });

      // ── ✅ Chart options with fixed legend ──────────────────────────────
      const dynamicOptions = {
        responsive: true,
        maintainAspectRatio: false,
        cutout: '60%',

        plugins: {
          legend: {
            position: 'bottom',
            labels: {
              // ✅ generateLabels — grouped, color matches chart
              generateLabels: () => {
                return Object.entries(typeGroups)
                  .filter(([, g]) => g.shares > 0)
                  .map(([label, g], i) => {
                    const percentage = totalShares > 0
                      ? ((g.shares / totalShares) * 100).toFixed(2)
                      : '0.00';
                    return {
                      text: `${label} (${percentage}%)`,
                      fillStyle: g.color,       // ✅ matches chart segment color
                      strokeStyle: 'transparent',
                      hidden: false,
                      // Store indices for click handler
                      _indices: g.indices,
                      index: i,
                    };
                  });
              },
            },

            // ✅ onClick — toggle correct dataset segments by stored indices
            onClick: (e, legendItem, legend) => {
              const chart = legend.chart;
              const indices = legendItem._indices || [];
              if (!indices.length) return;

              // Check if first index is hidden — toggle all in group
              const firstMeta = chart.getDatasetMeta(0).data[indices[0]];
              const isHidden = firstMeta.hidden;

              indices.forEach(idx => {
                const meta = chart.getDatasetMeta(0).data[idx];
                meta.hidden = !isHidden;
              });

              chart.update();
            },
          },

          tooltip: {
            callbacks: {
              label: (context) => {
                const value = context.raw || 0;
                const percentage = totalShares > 0
                  ? ((value / totalShares) * 100).toFixed(2)
                  : 0;
                return `${context.label}: ${value.toLocaleString()} shares (${percentage}%)`;
              },
            },
          },

          datalabels: {
            color: '#092840',
            font: { weight: '600', size: 12 },
            formatter: (value) => {
              const percentage = totalShares > 0
                ? ((value / totalShares) * 100).toFixed(2)
                : 0;
              return parseFloat(percentage) > 2 ? percentage + '%' : '';
            },
          },
        },
      };

      setPostMoneyChartOptions(dynamicOptions);

    } catch (err) {
      console.error("Error fetching chart:", err);
    }
  };

  return (
    <div className='investor-reports'>
      <div className='investor-reports__header'>
        <h4>Current Round Statistics</h4>
      </div>
      <div className='investor-reports__list'>
        <div className='round-chart' style={{ height: "420px" }}>
          {postMoneyChartData && postMoneyChartOptions ? (
            <Doughnut
              ref={chartRef}
              data={postMoneyChartData}
              options={postMoneyChartOptions}
            />
          ) : (
            <div>Round not found</div>
          )}
        </div>
      </div>
    </div>
  );
}