import React, { useState, useEffect } from "react";
import { API_BASE_URL } from '../../config/config';
import axios from "axios";


export default function InvestorReports() {
  const apiUrlRound = API_BASE_URL + "api/user/companydashboard/";
  const storedUsername = localStorage.getItem("SignatoryLoginData");
  const userLogin = storedUsername ? JSON.parse(storedUsername) : null;
  const access_token = userLogin?.access_token;
  const [fundingData, setfundingData] = useState('');
  useEffect(() => {
    getlatestfundingRoundDate();
  }, []);

  const getlatestfundingRoundDate = async () => {

    let formData = {
      company_id: userLogin.companies[0].id,
    };

    try {

      const res = await axios.post(
        apiUrlRound + "getlatestfundingRoundDate",
        formData,
        {
          headers: {
            Accept: "application/json",
            "Content-Type": "application/json",
            'Authorization': `Bearer ${access_token}`,
          },
        }
      );
      if (res.data.results.length > 0) {
        setfundingData(res.data.results[0]);
      }

    }
    catch (err) {

      console.error("Error fetching chart:", err);

    }
  };
  function formatCurrentDate(input) {
    const date = new Date(input);

    if (isNaN(date)) return "";
    const months = [
      "Jan", "Feb", "Mar", "Apr", "May", "Jun",
      "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
    ];

    const day = date.getDate();
    const month = months[date.getMonth()];
    const year = date.getFullYear();

    const getOrdinal = (n) => {
      if (n >= 11 && n <= 13) return "th";
      switch (n % 10) {
        case 1:
          return "st";
        case 2:
          return "nd";
        case 3:
          return "rd";
        default:
          return "th";
      }
    };

    return `${month} ${day}${getOrdinal(day)}, ${year}`;
  }
  const reports = [
    { id: 1, title: 'Q1 2026 Investor Update', timestamp: 'February 15, 2026' },
    { id: 2, title: 'Annual Performance Report', timestamp: 'January 10, 2026' },
    {
      id: 3, title: 'Funding Round Summary', timestamp: fundingData?.funding_summary_date
        ? formatCurrentDate(fundingData.funding_summary_date)
        : 'N/A'
    }
  ]
  return (
    <div className='investor-reports'>
      <div className='investor-reports__header d-flex align-items-center flex-wrap gap-3'>
        <h4>Investor Reports</h4>
        <button
          className='py-2 bg_primary creditb'
          onClick={() => (window.location.href = '/investorlist')}
        >
          Create Investor Report
        </button>
      </div>

      <div className='investor-reports__list'>
        {reports.map(report => (
          <a
            key={report.id}
            href={`/report/${report.id}`}
            className='investor-reports__item'
          >
            <span className='investor-reports__title'>{report.title}</span>
            <span className='investor-reports__date'>{report.timestamp}</span>
          </a>
        ))}
      </div>
    </div>
  )
}
